// 1. Чутливість до регістру
console.log("Це працює");
console.log("Це теж працює");

// 2. Коментарі
// Це мій перший коментар
/* 
   Багаторядковий коментар
   Можна писати багато рядків
*/

// 3. Крапка з комою
console.log("Рядок 1");
console.log("Рядок 2")
console.log("Рядок 3"); // можна і з крапкою, і без

// Приклад з помилкою (розкоментуйте, щоб побачити помилку)
// Console.log("Це не спрацює")`},{title:"Перевірка",bullets:["Збережіть файл.","Відкрийте `index.html` через Live Server.","Натисніть `F12 → Console`.","У консолі повинні з'явитися всі повідомлення без помилок."]}],homework:{title:"Домашнє завдання",tasks:["Напишіть у `script.js` 3 однострокових коментарі.","Додайте 1 багаторядковий коментар.","Напишіть 5 `console.log()` з різним текстом: своє ім'я, місто, що ви вивчаєте тощо.","Намірно зробіть 1 помилку з регістром і подивіться, що покаже консоль.","Виправте помилку і переконайтеся, що код знову працює.","Напишіть у чаті: `Урок 4 пройдено`."]}}}];function Vv(e){return Xa.find(t=>t.slug===e)}const zv=["Основи JavaScript: змінні, функції, масиви, об'єкти","Сучасний синтаксис ES6+ без перевантаження теорією","Роботу з DOM, подіями та інтерактивними елементами","Створення перших практичних проєктів для портфоліо"],Fv=[{label:"Формат",value:"42 короткі уроки",icon:lf},{label:"Тривалість",value:"6–8 тижнів",icon:Pg},{label:"Мова",value:"Українська",icon:Ag},{label:"Старт",value:"Для новачків",icon:sf}],Mv=[{title:"Модуль 1. Знайомство з JavaScript",range:"Уроки 1–4",icon:Ya,items:["Що таке JavaScript і де він використовується","Як підготувати середовище","Перша програма і console.log","Базовий синтаксис без типових помилок"]},{title:"Модуль 2. Основи",range:"Уроки 5–12",icon:Lg,items:["Змінні, типи даних і перетворення типів","Оператори, шаблонні рядки і введення даних","Перші прості калькулятори","Відлагодження через console і breakpoints"]},{title:"Модуль 3. Керуючі конструкції",range:"Уроки 13–18",icon:Ig,items:["if...else, switch і тернарний оператор","Цикли while, do...while, for, for...of","Мислення через умови і повторення","Мініігри та практичні вправи"]},{title:"Модуль 4. Функції",range:"Уроки 19–24",icon:Tg,items:["Function Declaration, Expression, Arrow Functions","Параметри, default values і return","Scope і closure без зайвого академізму","Функції-калькулятори та валідація"]},{title:"Модуль 5. Масиви та об'